head.script:
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -2);

scwin.loginClntNo = $c.data.getMemInfo("clntNo") ?? "";
scwin.loginClntNm = $c.data.getMemInfo("clntNm") ?? ""; //거래처명
scwin.userClsCd = $c.data.getMemInfo("userClsCd") ?? "";	// 사용자 구분코드

scwin.menuParam = $c.data.getParameter().menuInfo.menuParam;
scwin.v_hhio = scwin.menuParam.hhio ?? "";

//<!-- House BL조회 확인   -->
scwin.hd_kcomcd = "DBEX";

scwin.onpageload = function () {
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    // f_setDSHeader(ds_retrieve, "1");
    // f_setDSHeader(ds_bookingList, "2");
    scwin.f_set("ONLOAD");
    scwin.f_DefaultValue();
    lc_iogb.setValue(scwin.v_hhio == "" ? "O" : scwin.v_hhio);

    // TEST DATA
    //ed_cnd_ed_bkEtdFrom.setValue("20160419");
    //ed_cnd_ed_bkEtdTo.setValue("20160419");
};

//---------------------------------------------------------
// function name : f_set
// function desc : 화면 open시 초기 데이타 setting
//---------------------------------------------------------
scwin.f_set = function (gubun) {
    switch (gubun) {
        case "ONLOAD":
            $c.gus.cfDisableKey();

            ed_cnd_ed_bkEtdFrom.setValue(scwin.strPreDate);
            ed_cnd_ed_bkEtdTo.setValue(scwin.strCurDate);

            rd_cnd_rd_bkbltype.setValue("");

            ed_cnd_ed_bkNo.focus();
            break;

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
            break;

        case "DELETE":
            $c.gus.cfDisableBtn();
            break;
    }
};

//-------------------------------------------------------------------------
// function name : f_DefaultValue
// function desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    lc_iogb.setValue("O");
    lc_flag.setValue("0");
};


