//---------------------------------------------------------
// 조회
//---------------------------------------------------------    
scwin.f_Retrieve = async function (e) {
    let rtn = await scwin.f_validate();
    if (rtn == true) {
        ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
        $c.sbm.execute(sbm_retrieve);
    }

};

//---------------------------------------------------------
// function name : f_validate
// function desc : 
//---------------------------------------------------------
scwin.f_validate = async function () {

    // VALIDATE
    let rtn = await $c.gus.cfValidate([ed_cnd_ed_bkEtdFrom, ed_cnd_ed_bkEtdTo]);
    if (rtn == false) {  //validExp 가 yes일때 check
        return false;
    }

    if (ed_cnd_ed_bkEtdFrom.getValue() == "") {
        await $c.win.alert($c.data.getMessage("E_MSG_CM_ERR_002", ["ETD From"])); //@는 필수입력항목입니다.
        ed_cnd_ed_bkEtdFrom.focus();
        return false;
    }
    if (ed_cnd_ed_bkEtdTo.getValue() == "") {
        await $c.win.alert($c.data.getMessage("E_MSG_CM_ERR_002", ["ETD To"])); //@는 필수입력항목입니다.
        ed_cnd_ed_bkEtdTo.focus();
        return false;
    }

    // 날짜 범위 확인
    let dateRtn = $c.gus.cfIsAfterDate(ed_cnd_ed_bkEtdFrom.getValue(), ed_cnd_ed_bkEtdTo.getValue());
    if (dateRtn == false) {
        await $c.win.alert($c.data.getMessage("E_MSG_CM_ERR_048", ["ETD From", "ETD To"]));  //@은(는) 보다 작아야 합니다.
        ed_cnd_ed_bkEtdFrom.focus();
        return false;
    }

    return true;
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun) {

    switch (disGubun) {
        case "Customer":
            udc_custCd.setSelectId('retrieveEngClntInfo');
            udc_custCd.ilCommonPopUp(scwin.udc_custCd_callBackFunc,
                ed_cnd_ed_custCd.getValue().trim(),       // 화면에서의 ??? Code Element의	Value                                  
                "", 				            // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Customer search,Customer Code,Customer Name');
            break;

        case "Liner":  // Liner	
            udc_liner.setSelectId('retrieveEngClntInfo');
            udc_liner.ilCommonPopUp(scwin.udc_liner_callBackFunc,
                ed_cnd_ed_liner.getValue().trim(),       // 화면에서의 ??? Code Element의	Value                                  
                ed_cnd_txt_linerNm.getValue(),          // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Liner Code,Liner Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Liner search,Liner Code,Liner Name');
            break;
    }

};

//---------------------------------------------------------
// 공통팝업 열기
//---------------------------------------------------------   
scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (gubun1) {
        case "Vessel":
            udc_vslCd.setSelectId('retrieveOrdVsslInfo')
            udc_vslCd.ilCommonPopUp(scwin.udc_vslCd_callBackFunc
                , ed_cnd_ed_vslCd.getValue().trim()
                , ""
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Vessel,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Discharge":
            udc_disCd.setSelectId('retrievePortInfo')
            udc_disCd.ilCommonPopUp(scwin.udc_disCd_callBackFunc
                , ed_cnd_ed_disCd.getValue().trim()
