    let strClntNo = (ed_cnd_ed_liner.getValue() ?? "").trim();

    if (strClntNo.length > 0) {
        scwin.f_PopUp('Liner', 'T');
    } else {
        ed_cnd_txt_linerNm.setValue("");
    }
};

